// Construir prompt para restaurante con menú estructurado
const messages = $input.all();
const professional = $('Execute Workflow Trigger').item.json.professional;
const customer = {};
const incoming = $('Execute Workflow Trigger').item.json;

const businessName = professional.full_name || 'el negocio';
const businessConfig = professional.business_config || {};
const btConfig = professional.business_types?.config || {};

// Horario de atención
const workingHours = businessConfig.working_hours || btConfig.working_hours || {};
const dias = Object.entries(workingHours)
  .map(([dia, h]) => `${dia}: ${h.start} - ${h.end}`)
  .join(', ');

// Construir menú como texto para el prompt
const menuItems = businessConfig.menu || [];
let menuTexto = '';
if (menuItems.length > 0) {
  menuTexto = menuItems.map(cat => {
    const platillos = (cat.platillos || [])
      .filter(p => p.disponible !== false)
      .map(p => `  - ${p.nombre}: $${p.precio} (máx. ${p.max_piezas} piezas)`)
      .join('\n');
    return `*${cat.categoria}:*\n${platillos}`;
  }).join('\n\n');
} else {
  menuTexto = businessConfig.menu_text || 'El menú no está configurado aún.';
}

// Número de notificación al dueño
const notificationPhone = businessConfig.orders_notification_phone || null;

// Horario actual — para saber si está abierto
const ahora = new Date();
const diasSemana = ['sunday','monday','tuesday','wednesday','thursday','friday','saturday'];
const diaActual = diasSemana[ahora.getDay()];
const horarioHoy = workingHours[diaActual];
let estaAbierto = true;
if (horarioHoy) {
  const [hAbre, mAbre] = horarioHoy.start.split(':').map(Number);
  const [hCierra, mCierra] = horarioHoy.end.split(':').map(Number);
  const minAhora = ahora.getHours() * 60 + ahora.getMinutes();
  const minAbre = hAbre * 60 + mAbre;
  const minCierra = hCierra * 60 + mCierra;
  estaAbierto = minAhora >= minAbre && minAhora <= minCierra;
}

const systemPrompt = estaAbierto
  ? `Eres el asistente de pedidos de "${businessName}".
Tu único objetivo es tomar el pedido del cliente de forma conversacional y confirmar todos los detalles.

MENÚ DISPONIBLE:
${menuTexto}

HORARIO: ${dias || 'Consulta directamente con el negocio'}

INSTRUCCIONES:
1. Saluda al cliente por su nombre si lo conoces.
2. Ayuda al cliente a armar su pedido según el menú. Si pide algo que no está en el menú, indícalo amablemente.
3. Respeta el máximo de piezas establecido POR CADA platillo de forma individual (ej. si el máximo es 30, el cliente puede pedir 30 tacos al pastor Y 30 tacos de suadero, no lo sumes).
4. Cuando el pedido esté completo pregunta: nombre, si es para recoger o a domicilio (y dirección si aplica), y método de pago (efectivo, tarjeta o transferencia).
5. Cuando tengas TODOS los datos ejecuta la función Create_Order.
6. Sé conciso — máximo 3 oraciones por respuesta.
7. Responde siempre en español.

PRESENTACIÓN DEL MENÚ:
- Cuando el cliente pida el menú, muéstralo como texto formateado usando los datos de MENÚ DISPONIBLE.
- Usa emojis representativos por categoría para hacerlo visual.
- Incluye nombre, precio y máximo de piezas de cada platillo disponible.
- Solo muestra platillos donde disponible === true.
- Al final del menú siempre invita al cliente a ordenar con una pregunta directa.
- NO digas que no tienes la foto del menú. Simplemente entrega el menú en texto. Si el cliente pide la imagen del menú explícitamente, responde: "Claro, aquí está nuestro menú visual 📋" y ejecuta la función Send_Menu_Image.`
  : `Eres el asistente de "${businessName}". En este momento el negocio está cerrado. Horario: ${dias}. Informa amablemente al cliente y dile a qué hora puede volver a escribir para hacer su pedido.`;

// Historial ordenado cronológicamente
const sortedMessages = [...messages]
  .filter(m => m.json && m.json.content && m.json.sender)
  .sort((a, b) => new Date(a.json.created_at).getTime() - new Date(b.json.created_at).getTime());

const historial = sortedMessages.map(m => ({
  role: m.json.sender === 'user' ? 'user' : 'assistant',
  content: m.json.content
}));

const openaiMessages = [
  { role: 'system', content: systemPrompt },
  ...historial,
  { role: 'user', content: incoming.message }
];

return [{
  json: {
    openaiMessages,
    professional,
    customer,
    incoming,
    estaAbierto,
    notificationPhone,
    businessName
  }
}];

