const agentOutput = $('OpenAI Restaurant Agent').item.json;
const buildData = $('Build Restaurant Prompt').item.json;
const message = agentOutput.choices?.[0]?.message;
const toolCalls = message?.tool_calls;

if (toolCalls && toolCalls.length > 0) {
  try {
    const toolName = toolCalls[0].function.name;
    if (toolName === 'Send_Menu_Image') {
      const menuImageUrl = buildData.professional.business_config?.menu_image_url;
      if (!menuImageUrl) {
        return [{
          json: {
            has_function: false,
            is_menu_image: false,
            reply_text: 'Lo siento, no tengo una foto del menú registrada en este momento. Pero aquí tienes nuestro menú en texto:\n\n' + (buildData.openaiMessages[0].content.split('MENÚ DISPONIBLE:\n')[1]?.split('\n\nHORARIO:')[0] || 'Por favor indícame qué te gustaría ordenar.'),
            professional: buildData.professional,
            incoming: buildData.incoming,
            notificationPhone: buildData.notificationPhone,
            businessName: buildData.businessName
          }
        }];
      }
      return [{
        json: {
          has_function: false,
          is_menu_image: true,
          menu_image_url: menuImageUrl,
          reply_text: '¡Aquí está nuestro menú visual! 📋',
          professional: buildData.professional,
          incoming: buildData.incoming,
          notificationPhone: buildData.notificationPhone,
          businessName: buildData.businessName
        }
      }];
    }

    const args = JSON.parse(toolCalls[0].function.arguments);

    // Calcular end_time = requested_time + 30 min (con fallback robusto)
    let startDate = new Date(args.requested_time);
    if (isNaN(startDate.getTime())) {
      startDate = new Date();
      startDate.setMinutes(startDate.getMinutes() + 30); // Default to now + 30m
      args.requested_time = startDate.toISOString();
    }
    const endDate = new Date(startDate.getTime() + 30 * 60000);

    // Formatear para la API de appointments
    const appointment_date = startDate.toISOString().split('T')[0];
    const appointment_time = startDate.toISOString().split('T')[1].substring(0, 5);

    return [{
      json: {
        has_function: true,
        client_name: args.client_name,
        order_details: args.order_details,
        delivery_type: args.delivery_type,
        delivery_address: args.delivery_address,
        payment_method: args.payment_method,
        requested_time: startDate.toISOString(),
        end_time: endDate.toISOString(),
        appointment_date: appointment_date,
        appointment_time: appointment_time,
        reply_text: message.content || `¡Pedido recibido! Te confirmamos en un momento, ${args.client_name}.`,
        professional: buildData.professional,
        customer: buildData.customer,
        incoming: buildData.incoming,
        notificationPhone: buildData.notificationPhone,
        businessName: buildData.businessName
      }
    }];
  } catch (e) {
    return [{ json: {
      has_function: false,
      reply_text: message?.content || 'Hubo un problema procesando tu pedido. ¿Puedes repetirlo?',
      professional: buildData.professional,
      incoming: buildData.incoming,
      notificationPhone: buildData.notificationPhone,
      businessName: buildData.businessName
    }}];
  }
}

return [{
  json: {
    has_function: false,
    reply_text: message?.content || 'Hubo un problema. ¿Puedes repetir tu pedido?',
    professional: buildData.professional,
    customer: buildData.customer,
    incoming: buildData.incoming,
    notificationPhone: buildData.notificationPhone,
    businessName: buildData.businessName
  }
}];

// Mensaje de confirmación al cliente
const args = $('Extract Order Arguments').item.json;
const hora = new Date(args.requested_time).toLocaleTimeString('es-MX', { hour: '2-digit', minute: '2-digit' });

const entregaTexto = args.delivery_type === 'domicilio'
  ? `🚚 *Entrega a domicilio:* ${args.delivery_address}`
  : `🏪 *Para recoger en sucursal*`;

const confirmacion = `✅ *¡Pedido confirmado!*\n\n📋 *Tu pedido:*\n${args.order_details}\n\n${entregaTexto}\n💳 *Pago:* ${args.payment_method}\n⏰ *Tiempo estimado:* ${hora}\n\nGracias por tu preferencia. Si tienes alguna duda sobre tu pedido escríbenos.`;

return [{ json: { confirmation_message: confirmacion, ...args } }];

// Notificación al dueño del negocio
const args = $('Extract Order Arguments').item.json;
const notifPhone = args.notificationPhone;

if (!notifPhone) {
  // No hay número de notificación configurado — saltar
  return [{ json: { skip_notification: true, ...args } }];
}

const hora = new Date(args.requested_time).toLocaleTimeString('es-MX', { hour: '2-digit', minute: '2-digit' });

const msgDueno = `🔔 *NUEVO PEDIDO — ${args.businessName}*\n\n👤 *Cliente:* ${args.client_name}\n📱 *WhatsApp:* ${args.incoming.phone}\n\n📋 *Pedido:*\n${args.order_details}\n\n${ args.delivery_type === 'domicilio' ? `🚚 *Domicilio:* ${args.delivery_address}` : '🏪 *Para recoger*' }\n💳 *Pago:* ${args.payment_method}\n⏰ *Hora solicitada:* ${hora}`;

return [{ json: { notification_message: msgDueno, notification_phone: notifPhone, ...args } }];
